import { useState } from "react";

const App = () => {
  const [selected, setSelected] = useState({});

  const questions = [
    {
      id: 1,
      question: "Which sensor is used to measure sound intensity in decibels (dB)?",
      options: ["PIR Sensor", "Analog SPL Meter", "LDR", "DHT11"]
    },
    {
      id: 2,
      question: "Which technology detects stationary presence via micro-movements?",
      options: ["Ultrasonic", "Passive Infrared", "mmWave Radar", "Photoresistor"]
    }
  ];

  const handleSelect = (qid, opt) => {
    setSelected((prev) => ({ ...prev, [qid]: opt }));
  };

  return (
    <div style={styles.container}>
      <div style={styles.wrapper}>

        {/* SLIM HEADER */}
        <header style={styles.header}>
          <h1 style={styles.logo}>QUIZZLY <span style={styles.vTag}>V1</span></h1>
          <p style={styles.user}>Harshith B • 23MIS0012</p>
        </header>

        {/* TWO CARDS ONLY - FORCED 50/50 SPLIT */}
        <div style={styles.quizArea}>
          {questions.map((q) => (
            <div key={q.id} style={styles.qCard}>
              <h2 style={styles.qTitle}>{q.id}. {q.question}</h2>
              <div style={styles.optGrid}>
                {q.options.map((opt) => {
                  const isActive = selected[q.id] === opt;
                  return (
                    <button
                      key={opt}
                      onClick={() => handleSelect(q.id, opt)}
                      style={{ ...styles.optBtn, ...(isActive ? styles.optActive : {}) }}
                    >
                      <div style={{ ...styles.dot, borderColor: isActive ? "#6366f1" : "#334155" }}>
                        {isActive && <div style={styles.dotInner} />}
                      </div>
                      {opt}
                    </button>
                  );
                })}
              </div>
            </div>
          ))}
        </div>

        {/* ACTION FOOTER */}
        <footer style={styles.footer}>
          <button 
            onClick={() => alert("Submitted! Ready for V2 logic.")} 
            style={styles.submitBtn}
          >
            Submit Quiz
          </button>
        </footer>
      </div>
    </div>
  );
};

const styles = {
  container: {
    height: "100vh",
    width: "100vw",
    backgroundColor: "#020617", // Dark background (no white edges)
    color: "#f1f5f9",
    fontFamily: "'Inter', sans-serif",
    margin: 0,
    padding: 0,
    overflow: "hidden", // STRICT NO SCROLL
    display: "flex",
    justifyContent: "center",
  },
  wrapper: {
    width: "100%",
    maxWidth: "850px",
    display: "flex",
    flexDirection: "column",
    padding: "20px", // Reduced padding to fit screen better
  },
  header: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    marginBottom: "15px",
  },
  logo: { fontSize: "18px", fontWeight: "900", margin: 0 },
  vTag: { color: "#6366f1", fontSize: "10px" },
  user: { fontSize: "12px", color: "#64748b", margin: 0 },

  quizArea: {
    flex: 1, // Uses all remaining vertical space
    display: "flex",
    flexDirection: "column",
    gap: "15px",
  },
  qCard: {
    flex: 1, // Forces two questions to take 50% height each
    background: "#0f172a",
    border: "1px solid #1e293b",
    borderRadius: "12px",
    padding: "20px",
    display: "flex",
    flexDirection: "column",
    justifyContent: "center",
  },
  qTitle: { fontSize: "16px", margin: "0 0 15px 0", fontWeight: "600" },

  optGrid: { 
    display: "grid", 
    gridTemplateColumns: "1fr 1fr", 
    gap: "10px" 
  },
  optBtn: {
    all: "unset",
    padding: "12px 15px",
    background: "#1e293b50",
    border: "1px solid #1e293b",
    borderRadius: "8px",
    cursor: "pointer",
    display: "flex",
    alignItems: "center",
    fontSize: "13px",
    transition: "0.2s"
  },
  optActive: { borderColor: "#6366f1", background: "#6366f115" },
  dot: { width: "12px", height: "12px", border: "2px solid", borderRadius: "50%", marginRight: "10px", display: "flex", alignItems: "center", justifyContent: "center" },
  dotInner: { width: "6px", height: "6px", background: "#6366f1", borderRadius: "50%" },

  footer: {
    height: "60px",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    marginTop: "10px",
  },
  submitBtn: {
    all: "unset",
    background: "#6366f1",
    padding: "10px 40px",
    borderRadius: "8px",
    fontWeight: "bold",
    cursor: "pointer",
    fontSize: "14px",
    boxShadow: "0 4px 14px 0 rgba(99, 102, 241, 0.39)",
  }
};

export default App;
